import React, { useState, useRef } from "react";

export default function Profile() {
  const storedUser = JSON.parse(localStorage.getItem("user") || "{}");
  const fileRef = useRef(null);
  const [photo, setPhoto] = useState(localStorage.getItem("profile_photo") || null);
  const [profile, setProfile] = useState({
    name: storedUser.name||"", email: storedUser.email||"",
    phone: storedUser.phone||"", role: storedUser.role||"",
    bio: storedUser.bio||"", skills: storedUser.skills||"",
  });
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState("");

  const handleChange = (e) => setProfile({...profile,[e.target.name]:e.target.value});

  const handlePhoto = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 2*1024*1024) { alert("Max 2MB"); return; }
    const reader = new FileReader();
    reader.onloadend = () => { setPhoto(reader.result); localStorage.setItem("profile_photo",reader.result); };
    reader.readAsDataURL(file);
  };

  const save = () => {
    setSaving(true);
    localStorage.setItem("user", JSON.stringify({...storedUser,...profile}));
    setTimeout(() => { setSaving(false); setSuccess("Saved!"); setTimeout(()=>setSuccess(""),3000); }, 600);
  };

  const inp = { width:"100%", padding:"10px 14px", border:"1.5px solid #e2e8f0", borderRadius:"8px", fontSize:"13px", outline:"none", background:"white", color:"#0f172a", boxSizing:"border-box" };
  const inpDis = { ...inp, background:"#f8fafc", color:"#94a3b8", border:"1.5px solid #f1f5f9" };
  const lbl = { fontSize:"11px", fontWeight:"700", color:"#64748b", display:"block", marginBottom:"5px", textTransform:"uppercase", letterSpacing:"0.8px" };

  return (
    <div style={{ background:"#f8fafc", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" }}>
      <h1 style={{ fontSize:"24px", fontWeight:"700", color:"#0f172a", margin:"0 0 4px" }}>My Profile</h1>
      <p style={{ color:"#64748b", fontSize:"13px", marginBottom:"28px" }}>Manage your account information</p>

      {success && <div style={{ background:"#dcfce7", border:"1px solid #86efac", color:"#15803d", padding:"10px 16px", borderRadius:"8px", fontSize:"13px", marginBottom:"16px" }}>✅ {success}</div>}

      <div style={{ background:"white", border:"1px solid #e2e8f0", borderRadius:"16px", padding:"28px", maxWidth:"680px", boxShadow:"0 1px 4px rgba(0,0,0,0.04)" }}>

        {/* PHOTO ROW */}
        <div style={{ display:"flex", alignItems:"center", gap:"20px", marginBottom:"28px", paddingBottom:"24px", borderBottom:"1px solid #f1f5f9" }}>
          {photo
            ? <img src={photo} alt="Profile" style={{ width:"72px", height:"72px", borderRadius:"50%", objectFit:"cover", border:"3px solid #0f766e", flexShrink:0 }} />
            : <div style={{ width:"72px", height:"72px", borderRadius:"50%", background:"linear-gradient(135deg,#0f766e,#0891b2)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:"26px", fontWeight:"800", color:"white", border:"3px solid #0f766e", flexShrink:0 }}>
                {profile.name?.charAt(0)?.toUpperCase()||"?"}
              </div>
          }
          <div>
            <p style={{ fontSize:"18px", fontWeight:"700", color:"#0f172a", margin:"0 0 2px" }}>{profile.name}</p>
            <p style={{ fontSize:"13px", color:"#64748b", margin:"0 0 6px" }}>{profile.email}</p>
            <span style={{ display:"inline-block", padding:"3px 10px", borderRadius:"20px", fontSize:"11px", fontWeight:"700", background:"#f0fdf9", color:"#0f766e", border:"1px solid #99f6e4", textTransform:"capitalize" }}>{profile.role}</span>
            <div style={{ display:"flex", gap:"8px", marginTop:"8px" }}>
              <button onClick={() => fileRef.current.click()}
                style={{ padding:"6px 14px", borderRadius:"7px", border:"1px solid #99f6e4", background:"#f0fdf9", color:"#0f766e", fontSize:"11px", fontWeight:"600", cursor:"pointer" }}>
                📷 Change Photo
              </button>
              {photo && <button onClick={() => { setPhoto(null); localStorage.removeItem("profile_photo"); }}
                style={{ padding:"6px 14px", borderRadius:"7px", border:"1px solid #fca5a5", background:"#fff1f2", color:"#dc2626", fontSize:"11px", fontWeight:"600", cursor:"pointer" }}>
                🗑 Remove
              </button>}
            </div>
            <p style={{ fontSize:"10px", color:"#94a3b8", marginTop:"4px" }}>JPG, PNG — Max 2MB</p>
          </div>
          <input type="file" ref={fileRef} onChange={handlePhoto} accept="image/jpeg,image/png,image/webp" style={{ display:"none" }} />
        </div>

        {/* GRID FIELDS */}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"16px", marginBottom:"16px" }}>
          <div><label style={lbl}>Full Name</label><input name="name" value={profile.name} onChange={handleChange} style={inp} /></div>
          <div><label style={lbl}>Phone</label><input name="phone" value={profile.phone} onChange={handleChange} placeholder="+91 98765 43210" style={inp} /></div>
          <div><label style={lbl}>Email</label><input value={profile.email} disabled style={inpDis} /></div>
          <div><label style={lbl}>Role</label><input value={profile.role} disabled style={{...inpDis,textTransform:"capitalize"}} /></div>
        </div>

        <div style={{ marginBottom:"16px" }}>
          <label style={lbl}>Skills <span style={{ color:"#94a3b8", fontWeight:"400", textTransform:"none" }}>(comma separated)</span></label>
          <input name="skills" value={profile.skills} onChange={handleChange} placeholder="React, Node.js, MySQL..." style={inp} />
        </div>

        <div style={{ marginBottom:"24px" }}>
          <label style={lbl}>Bio</label>
          <textarea name="bio" value={profile.bio} onChange={handleChange} rows={3} placeholder="Tell clients about yourself, your experience and expertise..."
            style={{ ...inp, resize:"none", lineHeight:1.5 }} />
        </div>

        <button onClick={save} disabled={saving}
          style={{ padding:"11px 28px", borderRadius:"9px", border:"none", background:"linear-gradient(135deg,#0f766e,#0891b2)", color:"white", fontSize:"13px", fontWeight:"700", cursor:"pointer", opacity:saving?.7:1 }}>
          {saving?"Saving...":"Save Profile"}
        </button>
      </div>
    </div>
  );
}
